import sys, importlib, hou, traceback
try:
    MOD_NAME = "nimbus.nimbus_hip_open"
    sys.modules.pop(MOD_NAME, None)
    mod = importlib.import_module(MOD_NAME)

    for fn in ("_show_dialog", "show_dialog", "main"):
        if hasattr(mod, fn):
            getattr(mod, fn)()
            break
    else:
        hou.ui.displayMessage("Nimbus Hip Open loaded, but no entry function found.")
except Exception:
    hou.ui.displayMessage("Nimbus Hip Open launch error:\n" + traceback.format_exc())

